VALUES
  ('cpa-moex-00768', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依加值型及非加值型營業稅法之規定，營業人若同時設有總機構及分支機構者，其有關稅籍登記 應如何辦理？ 由總機構代為申請稅籍登記即可，該等分支機構無須自行申請稅籍登記 僅總機構須申請稅籍登記，該等分支機構無須另行個別申請稅籍登記 總機構須申請稅籍登記，該等分支機構亦須自行申請稅籍登記 皆無須申請稅籍登記', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00769', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '土地所有權人出售土地後，另行購買土地，合於規定者，得申請退還已納土地增值稅，依土地稅 法規定，下列敘述何者錯誤？ 適用於自用住宅用地、自營工廠用地及自耕之農業用地 土地所有權人先購買土地後，自完成移轉登記之日起2年內，始行出售土地者，準用退還之規定 重購之土地，自完成移轉登記之日起，5年內再行移轉，應追繳原退還稅款 應向重購土地所在地之稽徵機關辦理退還申請', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00770', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '經依復查、訴願或行政訴訟程序終結決定或判決有應補繳稅額者，除填發補稅單外，應依下列何 種利率按日加計利息一併徵收？ 按該決定或判決日當日郵政儲金一年期定期儲金固定利率 按該決定或判決日當年度郵政儲金一年期定期儲金固定利率 按各年度一月一日臺灣銀行一年期定期儲金固定利率 按各年度一月一日郵政儲金一年期定期儲金固定利率', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00771', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，公告現值係指直轄市及縣（市）政府依何種法律公告之土地現值？ 土地法  土地稅法施行細則  土地現值辦法  平均地權條例', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00772', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，一般土地之地價稅稅率，可分為幾個級距？ 3個  4個  5個  6個', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00773', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依土地稅法規定，為增進社會福利，對於教育、醫療等用地，得予適當之減免，其減免標準，由 何機關定之？ 稅捐稽徵處  國稅局  財政部  行政院', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00774', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，納稅義務人如發現繳納通知文書有記載、計算錯誤或重複時，應如何為之？ 於規定繳納期間內，得要求稅捐稽徵機關查對更正 於規定繳納期間內，向稅捐稽徵機關申請復查 於繳納期間屆滿後，提起訴願 於繳納期間屆滿後，提起行政訴訟', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00775', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，營利事業依規定應給與他人憑證而未給與，應就其未給與憑證，經查明認定 之總額，處以罰鍰者，由下列何機關處分之？ 主管稽徵機關  財政部  地方法院  行政法院', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00776', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲於108年6月7日至稅捐稽徵機關申報其107年度綜合所得稅並繳納其應納稅額與滯納金，依 稅捐稽徵法規定，甲應申報繳納之107年度綜合所得稅的核課期間為幾年？ 1年  3年  5年  7年', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00777', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依稅捐稽徵法規定，下列何者非依稅籍底冊或查得資料核定課徵之稅捐？ 地價稅  房屋稅  使用牌照稅  貨物稅', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00778', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依所得稅法規定，下列何者不適用個人房地合一課徵所得稅？ 民國105年1月1日以後出售依農業發展條例申請興建之農舍 民國105年1月1日以後出售103年1月2日以後取得之房屋、土地，且持有期間在二年以內 出售民國105年1月1日以後取得之房屋、土地 出售民國105年1月1日以後取得以設定地上權方式之房屋使用權', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00779', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法規定，有關違反遺產稅及贈與稅規定之處罰，下列敘述何者錯誤？ 納稅義務人未依限辦理遺產稅或贈與稅申報者，按核定應納稅額加處二倍以下之罰鍰 納稅義務人對依規定應申報之遺產或贈與財產，已依規定申報而有漏報或短報情事，並無故意 以詐欺或其他不正當方法者，應按所漏稅額處以二倍以下之罰鍰 納稅義務人違反遺產及贈與稅法第八條之規定，於遺產稅未繳清前，分割遺產、交付遺贈或辦 理移轉登記，或贈與稅未繳清前，辦理贈與移轉登記者，處一年以下有期徒刑 納稅義務人逃漏遺產稅或贈與稅之罰鍰，連同應徵之稅款及加計之利息，最多不得超過遺產總 額或贈與總額', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00780', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲死亡後遺有下列四項財產，依遺產及贈與稅法規定，其中何項財產可以「不計入遺產總額」？ 銀行存款  上市（櫃）公司股票  自用住宅  甲創作之藝術品', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00781', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '依遺產及贈與稅法及其相關法規規定，遺產及贈與財產價值之計算，以被繼承人死亡時或贈與人 贈與時之時價為準，下列敘述何者錯誤？ 土地以公告土地現值或評定標準價格為準  典權以典價為其價額 房屋以評定標準價格為準  土地以公告地價為準', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00782', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲於107年12月31日在使用收銀機統一發票之超商花10元買口香糖一包，而該商店11月、12 月統一發票已用完，下列店員之處理何者符合加值型及非加值型營業稅法之規定？ 經主管稽徵機關核准者得開立108年1月、2月之統一發票 開立收據待次日再換統一發票 不開立發票，因未滿50元 開立107年9月、10月之統一發票', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00783', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲臥病在床多年，兩個兒子均居住在美國，一直以來均由非其配偶之乙照料生活起居，為了感謝 乙的照顧，在死亡前一個月將所有的積蓄新臺幣（下同）500萬元贈與乙，未辦理贈與稅申報就 死亡，甲贈與500萬元的行為該如何課稅？ 對甲的兩個兒子課贈與稅  500萬元列入甲的遺產課稅 對乙課贈與稅    對乙課所得稅', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00784', 'cpa', 'cpa-moex-108-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '甲在104年6月15日與A銀行訂立信託契約，在104年7月1日匯款1,000萬元為信託財產， 請A銀行投資有價證券5年，信託契約之受益人為甲本人，在108年2月1日甲請A銀行將受 益人變更為其獨生女乙，如何課徵贈與稅？ 以104年6月15日為贈與日，由甲申報贈與稅 以104年7月1日為贈與日，由乙申報贈與稅 以108年2月1日為贈與日，由甲申報贈與稅 以108年2月1日為贈與日，由乙申報贈與稅', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "2689da149a8e", "answer_pdf_sha1": "68437cc80423", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL);
